var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"짠- 어때?","JPN":"じゃーん、どう？","ENG":"Ta-da! What do you think?","TWN":"鏘—怎麼樣？"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"앞으론 이걸로 진짜 몸처럼 쓸 수 있을 거야.","JPN":"これで本物の肉体みたいに使えるはずだよ。","ENG":"Now, you'll be able to use this just like a real body.","TWN":"以後就可以用這個當作真正的身體了。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"…질량 부여 홀로그램인가. 과연 우수한 기술력이군.","JPN":"……質量付与ホログラムか。素晴らしい技術力だ。","ENG":"…A mass-enabled hologram. Quite the impressive tech.","TWN":"…是質量賦予全息圖嗎。果然是優秀的技術。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L5_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"감각도… 피부가 마치 살아있을 적으로 돌아간 기분이야.","JPN":"皮膚の感覚も……まるで生き返ったような気分だ。","ENG":"Even my senses… It feels like I've returned to the days when my body was still alive.","TWN":"連感覺…都像皮膚重新活過來一樣。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"고맙네, 테라브레인 소녀.","JPN":"礼を言う、テラブレイン少女。","ENG":"Thank you, Terrabrain girl.","TWN":"謝謝你，特拉大腦女孩。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L7_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"뭘, 아빠 친구한테 그쯤이야.","JPN":"いいよ、パパの友だちだから。","ENG":"No big deal. You're a friend of Daddy's, after all.","TWN":"沒什麼啦，你可是爸爸的朋友呢。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L9_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"편히 쉬어야 할 자넬 끌어들인 날 원망하게, 서생.","JPN":"ゆっくり休ませてやれなくてすまないな、ショウ。","ENG":"Sorry we couldn't let you rest, Seosaeng.","TWN":"書生，把你拉進來，你一定會怨我。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그리고 관리국에 흔쾌히 협력을 약속해줘서 고맙군.","JPN":"そして、快く管理局に協力してくれて感謝する。","ENG":"And thank you for agreeing to work with the Administration.","TWN":"不過，還是謝謝你爽快地答應和管理局合作。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"본인의 바람은 과거에 이루었으니, 이번엔 관리국 일원으로서의 소명을 다하러 돌아왔을 뿐이요.","JPN":"某の願いはすでに叶ったゆえ、今度は管理局の一員としての役目を果たすべく戻った次第である。","ENG":"My personal wish was fulfilled long ago. Now, I return solely to fulfill my duty as a member of the Administration.","TWN":"我的心願在過去就已經實現了，這次回來只是為了盡到管理局成員的職責。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"이렇게 다가올 미래를 마주할 수 있는 것만으로도… 본인에겐 더할 나위 없이 기쁜 일이라네.","JPN":"こうして来たる未来と向き合えるだけで……某にとっては身に余る祝福であろう。","ENG":"Just being able to do something again… is more than I deserve.","TWN":"光是能這樣面對即將到來的未來…對我來說就是無比快樂的事。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"강산이 변하는 세월 동안 많은 일들이 있었지.","JPN":"山河の移り変わりに合わせ、人の世にもいろんなことがあった。","ENG":"Many things have happened over the years, enough to change even the mountains and rivers.","TWN":"這幾年，滄海桑田，發生了很多事。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그날 자네가 만들어낸 흐름이 우리 모두를 이곳까지 이끈 거라네.","JPN":"あの日、君が生み出した流れが、私たちを「今」に導いてくれたのだ。","ENG":"It was the course you set in motion that led us all here that day.","TWN":"那天你創造的潮流，把我們所有人都帶到了這裡。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"많이 닮았더구려. 그 아이.","JPN":"よく似ていた、あの子。","ENG":"That child. He reminds me so much of her.","TWN":"那個孩子，長得很像呢。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"장한 아일세. 용혈이 내린 영겁의 저주를 제 손으로 기어코 끊어냈지.","JPN":"立派な子だ。龍血の永劫の呪いを、とうとう自分の手で断ち切った。","ENG":"He's done well. Broke the curse of the Dragon Blood with his own hands.","TWN":"真是個了不起的孩子。他用自己的手，親手切斷了龍血所降下的永劫詛咒。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"참 알다가도 모를 일이지 않소.","JPN":"世には不思議なことが多いものだ。","ENG":"Funny, isn't it?","TWN":"這件事真的很難理解。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"명달 대장이 보지 못한 미래가 그토록 가까이에 있었을 줄이야.","JPN":"アカタツ隊長が見れなかった未来が、これほど身近な場所にあったとは。","ENG":"Who would've thought the future Commander Myeongdal never got to see was so close.","TWN":"明達隊長看不到的未來，居然就在這麼近的地方。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그런 기적을 거쳤음에도… 우리에겐 아직 많은 난관이 남아 있다네.","JPN":"そんな奇跡を経ても……私たちの前にはまだ多くの逆境が残っている。","ENG":"And even after such a miracle… we still have no shortage of trials ahead.","TWN":"即使經歷了這樣的奇蹟…我們還有很多難關要面對。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"…클리포트 게임.","JPN":"……クリフォトゲーム。","ENG":"…The Qliphoth Game.","TWN":"…逆卡巴拉遊戲。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"그 정보와 관련해선 테라브레인에 집약된 데이터로 파악했소. 조만간 위험한 존재가 현실에 들이닥치리란 것도.","JPN":"あれについては、テラブレインに集積されたデータを通して把握している。近い内、禍々しき存在が現実を襲ってくるだろうということも。","ENG":"As for that, I understood it through the data compiled in the Terrabrain. We also know that a dangerous entity will soon break into the Normalside.","TWN":"我已經透過特拉大腦的資料掌握了相關情報。也知道不久後，將會有危險的存在降臨現實。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"그러니 부디 말씀해주시게.","JPN":"だから教えてくれたまえ。","ENG":"So please, tell me.","TWN":"所以，請告訴我。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"본인이, 그 아이들의 미래를 위해 무엇을 할 수 있는지.","JPN":"あの子たちの未来のために、某に何ができるのかを。","ENG":"What can I do to protect the children's future?","TWN":"我能為那些孩子們的未來，做些什麼。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};